import React, { useState, useEffect } from 'react';
import { 
  Box, 
  Typography, 
  InputBase, 
  IconButton, 
  Chip, 
  Grid, 
  Button, 
  Stack, 
  Select, 
  MenuItem, 
  FormControl, 
  Divider, 
  useMediaQuery,
  SwipeableDrawer,
  Container,
  Paper
} from '@mui/material';
import { 
  Search, 
  FilterList, 
  DirectionsCar, 
  LocalOffer, 
  Close, 
  Tune,
  TrendingUp,
  AccessTime,
  NewReleases
} from '@mui/icons-material';
import { styled, alpha, useTheme } from '@mui/material/styles';
import { motion, AnimatePresence } from 'framer-motion';
import { Link } from 'react-router-dom';
import CarCard from '../components/cards/CarCard';

// Стилизованные компоненты
const SearchContainer = styled(Box)(({ theme }) => ({
  position: 'relative',
  borderRadius: 16,
  backgroundColor: alpha(theme.palette.background.paper, 1),
  boxShadow: theme.palette.mode === 'light' 
    ? '0 4px 20px rgba(0,0,0,0.05)' 
    : '0 4px 20px rgba(0,0,0,0.2)',
  width: '100%',
  marginBottom: theme.spacing(3),
  transition: 'all 0.3s ease',
  '&:hover': {
    boxShadow: theme.palette.mode === 'light' 
      ? '0 6px 24px rgba(0,0,0,0.08)' 
      : '0 6px 24px rgba(0,0,0,0.25)',
  },
}));

const SearchIconWrapper = styled('div')(({ theme }) => ({
  padding: theme.spacing(0, 2),
  height: '100%',
  position: 'absolute',
  pointerEvents: 'none',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: alpha(theme.palette.text.secondary, 0.7),
}));

const StyledInputBase = styled(InputBase)(({ theme }) => ({
  width: '100%',
  '& .MuiInputBase-input': {
    padding: theme.spacing(1.8, 1.5, 1.8, 0),
    paddingLeft: `calc(1em + ${theme.spacing(4)})`,
    transition: theme.transitions.create('width'),
    width: '100%',
    fontSize: '0.95rem',
  },
}));

const FilterChip = styled(Chip)(({ theme }) => ({
  margin: theme.spacing(0, 0.5, 1, 0),
  backgroundColor: alpha(theme.palette.primary.main, 0.08),
  color: theme.palette.primary.main,
  fontWeight: 500,
  borderRadius: 12,
  '&.MuiChip-clickable:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.15),
  },
  '&.Mui-selected': {
    backgroundColor: alpha(theme.palette.primary.main, 0.8),
    color: theme.palette.common.white,
    '&:hover': {
      backgroundColor: theme.palette.primary.main,
    }
  }
}));

const CategoryChip = styled(Chip)(({ theme }) => ({
  margin: theme.spacing(0, 0.8, 1, 0),
  fontWeight: 500,
  borderRadius: 12,
  boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
  '&.MuiChip-clickable:hover': {
    boxShadow: '0 4px 12px rgba(0,0,0,0.12)',
  }
}));

const HeroContainer = styled(Box)(({ theme }) => ({
  borderRadius: 24,
  overflow: 'hidden',
  position: 'relative',
  height: 340,
  marginBottom: theme.spacing(4),
  background: 'linear-gradient(135deg, #1976D2 0%, #2196F3 100%)',
  color: 'white',
  boxShadow: '0 12px 30px rgba(25, 118, 210, 0.25)',
  [theme.breakpoints.down('md')]: {
    height: 300,
  },
  [theme.breakpoints.down('sm')]: {
    height: 'auto',
    paddingBottom: theme.spacing(4),
  },
}));

const HeroContent = styled(Box)(({ theme }) => ({
  zIndex: 1,
  padding: theme.spacing(5, 4, 4, 4),
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  position: 'relative',
  [theme.breakpoints.down('sm')]: {
    padding: theme.spacing(3, 2),
  },
}));

const HeroBackgroundEffect = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: 0,
  right: 0,
  width: '100%',
  height: '100%',
  background: 'radial-gradient(60% 80% at 70% 50%, rgba(255,255,255,0.08) 0%, rgba(255,255,255,0) 100%)',
  zIndex: 0,
}));

const HeroBackgroundCircle = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: '10%',
  right: '5%',
  width: 280,
  height: 280,
  borderRadius: '50%',
  background: 'rgba(255,255,255,0.08)',
  zIndex: 0,
  [theme.breakpoints.down('md')]: {
    width: 200,
    height: 200,
  },
}));

const HeroBackgroundCircleSmall = styled(Box)(({ theme }) => ({
  position: 'absolute',
  bottom: '10%',
  left: '10%',
  width: 140,
  height: 140,
  borderRadius: '50%',
  background: 'rgba(255,255,255,0.05)',
  zIndex: 0,
  [theme.breakpoints.down('md')]: {
    width: 100,
    height: 100,
  },
}));

const HeroImage = styled(Box)(({ theme }) => ({
  position: 'absolute',
  right: 0,
  bottom: 0,
  width: '45%',
  height: '85%',
  backgroundImage: `url('https://images.unsplash.com/photo-1583121274602-3e2820c69888?q=80&w=1500&auto=format&fit=crop')`,
  backgroundSize: 'cover',
  backgroundPosition: 'center',
  borderRadius: '80px 0 0 0',
  zIndex: 2,
  boxShadow: '-10px 10px 30px rgba(0,0,0,0.15)',
  transition: 'all 0.3s ease',
  '&::before': {
    content: '""',
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    background: 'linear-gradient(90deg, rgba(25,118,210,1) 0%, rgba(25,118,210,0) 40%)',
    borderRadius: '80px 0 0 0',
  },
  [theme.breakpoints.down('md')]: {
    width: '40%',
    borderRadius: '60px 0 0 0',
    '&::before': {
      borderRadius: '60px 0 0 0',
    }
  },
  [theme.breakpoints.down('sm')]: {
    display: 'none'
  },
}));

const SectionTitle = styled(Typography)(({ theme }) => ({
  fontWeight: 700,
  marginBottom: theme.spacing(2.5),
  display: 'flex',
  alignItems: 'center',
  '& .MuiSvgIcon-root': {
    marginRight: theme.spacing(1),
    color: theme.palette.primary.main
  }
}));

const FilterDrawerContent = styled(Box)(({ theme }) => ({
  width: 320,
  padding: theme.spacing(3),
  [theme.breakpoints.down('sm')]: {
    width: '100vw',
  },
}));

// Данные о розыгрышах
const carData = [
  {
    id: '1',
    title: 'BMW X5',
    image: 'https://images.unsplash.com/photo-1617469767053-3f7c8cff7a6d?q=80&w=1000&auto=format&fit=crop',
    description: 'Роскошный внедорожник премиум-класса с мощным двигателем и комфортным салоном',
    ticketsSold: 456,
    totalTickets: 1000,
    price: 1000,
    year: 2022,
    participants: 400,
    endDate: '15.12.2023',
    category: 'premium'
  },
  {
    id: '2',
    title: 'Mercedes-Benz S-Class',
    image: 'https://images.unsplash.com/photo-1618843479313-40f8afb4b4d8?q=80&w=1000&auto=format&fit=crop',
    description: 'Флагманский седан с передовыми технологиями и непревзойденным комфортом',
    ticketsSold: 789,
    totalTickets: 1500,
    price: 1500,
    year: 2023,
    participants: 700,
    endDate: '20.01.2024',
    category: 'premium'
  },
  {
    id: '3',
    title: 'Audi Q7',
    image: 'https://images.unsplash.com/photo-1612825173281-9a193378527e?q=80&w=1000&auto=format&fit=crop',
    description: 'Полноразмерный кроссовер с просторным салоном и современными технологиями',
    ticketsSold: 350,
    totalTickets: 1200,
    price: 1200,
    year: 2023,
    participants: 320,
    endDate: '05.02.2024',
    category: 'premium'
  },
  {
    id: '4',
    title: 'Tesla Model 3',
    image: 'https://images.unsplash.com/photo-1560958089-b8a1929cea89?q=80&w=1000&auto=format&fit=crop',
    description: 'Электрический седан с запасом хода до 500 км и инновационным автопилотом',
    ticketsSold: 890,
    totalTickets: 2000,
    price: 800,
    year: 2023,
    participants: 800,
    endDate: '10.12.2023',
    category: 'electric'
  },
];

// Категории
const categories = [
  { id: 'all', label: 'Все', icon: <DirectionsCar />, color: '#1976D2' },
  { id: 'premium', label: 'Премиум', icon: <TrendingUp />, color: '#9C27B0' },
  { id: 'electric', label: 'Электро', icon: <NewReleases />, color: '#00BFA5' },
  { id: 'ending', label: 'Скоро завершатся', icon: <AccessTime />, color: '#FF5722' },
];

// Фильтры цены
const priceFilters = [
  { id: 'all', label: 'Любая цена' },
  { id: 'under_1000', label: 'До 1000 ₽' },
  { id: '1000_2000', label: '1000-2000 ₽' },
  { id: 'over_2000', label: 'Более 2000 ₽' },
];

// Фильтры марки
const brandFilters = [
  { id: 'all', label: 'Все марки' },
  { id: 'bmw', label: 'BMW' },
  { id: 'mercedes', label: 'Mercedes' },
  { id: 'audi', label: 'Audi' },
  { id: 'tesla', label: 'Tesla' },
];

const HomePage: React.FC = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const isTablet = useMediaQuery(theme.breakpoints.down('md'));
  
  const [search, setSearch] = useState('');
  const [sort, setSort] = useState('newest');
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState('all');
  const [selectedPrice, setSelectedPrice] = useState('all');
  const [selectedBrand, setSelectedBrand] = useState('all');
  
  // Обработчики фильтрации
  const handleCategoryChange = (categoryId: string) => {
    setActiveCategory(categoryId);
  };
  
  // Открыть/закрыть drawer с фильтрами
  const toggleDrawer = (open: boolean) => {
    setDrawerOpen(open);
  };
  
  // Применить фильтры
  const applyFilters = () => {
    setDrawerOpen(false);
  };
  
  // Сбросить фильтры
  const resetFilters = () => {
    setSelectedPrice('all');
    setSelectedBrand('all');
  };
  
  // Анимации
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { 
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  };
  
  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.4 }
    }
  };
  
  return (
    <Container disableGutters sx={{ px: { xs: 1, sm: 2 } }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
      >
        <HeroContainer>
          <HeroBackgroundEffect />
          <HeroBackgroundCircle />
          <HeroBackgroundCircleSmall />
          <HeroContent>
            <Box sx={{ zIndex: 2, maxWidth: { xs: '100%', sm: '60%' } }}>
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2, duration: 0.5 }}
              >
                <Typography variant="h3" component="h1" sx={{ 
                  fontWeight: 800, 
                  mb: 1.5,
                  fontSize: { xs: '1.8rem', sm: '2.2rem', md: '2.5rem' }
                }}>
                  Выиграй автомобиль своей мечты
                </Typography>
              </motion.div>
              
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.3, duration: 0.5 }}
              >
                <Typography variant="body1" sx={{ 
                  mb: 3.5, 
                  opacity: 0.95,
                  fontSize: { xs: '0.95rem', sm: '1rem' },
                  maxWidth: '90%'
                }}>
                  Участвуй в розыгрышах роскошных автомобилей всего от 500 ₽. Более 250 победителей уже получили свои авто!
                </Typography>
              </motion.div>
              
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4, duration: 0.5 }}
              >
                <Button
                  variant="contained"
                  size="large"
                  startIcon={<DirectionsCar />}
                  sx={{
                    backgroundColor: 'white',
                    color: 'primary.main',
                    borderRadius: 3,
                    fontSize: { xs: '0.9rem', sm: '1rem' },
                    fontWeight: 600,
                    padding: theme.spacing(1.2, 3),
                    boxShadow: '0 8px 20px rgba(0,0,0,0.15)',
                    '&:hover': {
                      backgroundColor: alpha(theme.palette.common.white, 0.9),
                      boxShadow: '0 10px 25px rgba(0,0,0,0.2)',
                      transform: 'translateY(-2px)'
                    }
                  }}
                >
                  Участвовать сейчас
                </Button>
              </motion.div>
            </Box>
          </HeroContent>
          <HeroImage />
        </HeroContainer>
        
        {/* Категории (прокручиваемая строка) */}
        <Box sx={{ mb: 3, mt: 1 }}>
          <Stack 
            direction="row" 
            spacing={1} 
            sx={{ 
              overflowX: 'auto', 
              py: 1,
              px: 0.5,
              '&::-webkit-scrollbar': {
                display: 'none'
              },
              scrollbarWidth: 'none'
            }}
          >
            {categories.map((category) => (
              <CategoryChip
                key={category.id}
                icon={category.icon}
                label={category.label}
                clickable
                onClick={() => handleCategoryChange(category.id)}
                sx={{
                  backgroundColor: activeCategory === category.id 
                    ? alpha(category.color, 0.15) 
                    : theme.palette.background.paper,
                  color: activeCategory === category.id 
                    ? category.color
                    : theme.palette.text.primary,
                  borderWidth: 2,
                  borderStyle: 'solid',
                  borderColor: activeCategory === category.id 
                    ? alpha(category.color, 0.5)
                    : 'transparent',
                  fontWeight: activeCategory === category.id ? 600 : 500,
                  '& .MuiChip-icon': {
                    color: activeCategory === category.id ? category.color : 'inherit'
                  }
                }}
              />
            ))}
          </Stack>
        </Box>
        
        {/* Строка поиска и фильтров */}
        <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
          <SearchContainer sx={{ flex: 1 }}>
            <SearchIconWrapper>
              <Search />
            </SearchIconWrapper>
            <StyledInputBase
              placeholder="Поиск автомобилей..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </SearchContainer>
          
          <Paper 
            elevation={0} 
            sx={{ 
              borderRadius: 4, 
              overflow: 'hidden', 
              boxShadow: theme.palette.mode === 'light' 
                ? '0 4px 20px rgba(0,0,0,0.05)' 
                : '0 4px 20px rgba(0,0,0,0.2)',
            }}
          >
            <IconButton 
              aria-label="filter" 
              onClick={() => toggleDrawer(true)}
              sx={{ 
                height: '100%',
                width: 50,
                borderRadius: 0,
                backgroundColor: theme.palette.background.paper,
              }}
            >
              <Tune />
            </IconButton>
          </Paper>
        </Box>
        
        {/* Заголовок раздела */}
        <SectionTitle variant="h5">
          <LocalOffer fontSize="small" /> Актуальные розыгрыши
        </SectionTitle>
        
        {/* Список автомобилей */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <Grid container spacing={3}>
            {carData.map((car) => (
              <Grid item xs={12} sm={6} md={6} lg={4} key={car.id}>
                <motion.div variants={itemVariants}>
                  <CarCard
                    id={car.id}
                    title={car.title}
                    image={car.image}
                    description={car.description}
                    ticketsSold={car.ticketsSold}
                    totalTickets={car.totalTickets}
                    price={car.price}
                    year={car.year}
                    participants={car.participants}
                    endDate={car.endDate}
                  />
                </motion.div>
              </Grid>
            ))}
          </Grid>
          
          <Box sx={{ display: 'flex', justifyContent: 'center', mt: 5, mb: 2 }}>
            <Button 
              variant="outlined" 
              color="primary"
              size="large"
              sx={{ 
                borderRadius: 3, 
                textTransform: 'none', 
                px: 4,
                py: 1.2,
                fontWeight: 600,
                boxShadow: '0 4px 12px rgba(33, 150, 243, 0.15)',
                '&:hover': {
                  boxShadow: '0 6px 16px rgba(33, 150, 243, 0.25)',
                  transform: 'translateY(-2px)',
                  backgroundColor: alpha(theme.palette.primary.main, 0.05)
                }
              }}
            >
              Показать больше розыгрышей
            </Button>
          </Box>
        </motion.div>
        
        {/* Выдвижной фильтр */}
        <SwipeableDrawer
          anchor={isMobile ? 'bottom' : 'right'}
          open={drawerOpen}
          onClose={() => toggleDrawer(false)}
          onOpen={() => toggleDrawer(true)}
          PaperProps={{
            sx: {
              borderRadius: isMobile ? '24px 24px 0 0' : 0
            }
          }}
        >
          <FilterDrawerContent>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
              <Typography variant="h6" sx={{ fontWeight: 600 }}>
                Фильтры
              </Typography>
              <IconButton onClick={() => toggleDrawer(false)}>
                <Close />
              </IconButton>
            </Box>
            
            <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
              Цена билета
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mb: 3, flexWrap: 'wrap' }}>
              {priceFilters.map(filter => (
                <FilterChip 
                  key={filter.id}
                  label={filter.label} 
                  clickable 
                  onClick={() => setSelectedPrice(filter.id)}
                  className={selectedPrice === filter.id ? 'Mui-selected' : ''}
                />
              ))}
            </Stack>
            
            <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
              Марка автомобиля
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mb: 3, flexWrap: 'wrap' }}>
              {brandFilters.map(filter => (
                <FilterChip 
                  key={filter.id}
                  label={filter.label} 
                  clickable 
                  onClick={() => setSelectedBrand(filter.id)}
                  className={selectedBrand === filter.id ? 'Mui-selected' : ''}
                />
              ))}
            </Stack>
            
            <Divider sx={{ my: 2 }} />
            
            <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
              <Button 
                variant="text" 
                onClick={resetFilters}
                sx={{ 
                  color: theme.palette.text.secondary,
                  fontWeight: 500
                }}
              >
                Сбросить все
              </Button>
              <Button 
                variant="contained" 
                onClick={applyFilters}
                sx={{ 
                  boxShadow: '0 4px 12px rgba(33, 150, 243, 0.25)',
                  borderRadius: 3,
                  px: 3
                }}
              >
                Применить
              </Button>
            </Box>
          </FilterDrawerContent>
        </SwipeableDrawer>
      </motion.div>
    </Container>
  );
};

export default HomePage;
